import React, { useState } from 'react';
import { CartProvider } from './context/CartContext';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import FeaturedServices from './components/FeaturedServices';
import SearchSection from './components/SearchSection';
import ProductSection from './components/ProductSection';
import PromoBanner from './components/PromoBanner';
import './App.css';

function App() {
  const [searchResults, setSearchResults] = useState(null);

  const handleSearch = ({ searchTerm, category }) => {
    // In a real app, this would make an API call
    console.log('Search:', { searchTerm, category });
    // For now, just filter existing products
    const allProducts = [...recentProducts, ...bestSellers];
    const filtered = allProducts.filter(product => 
      product.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      product.category.toLowerCase().includes(searchTerm.toLowerCase())
    );
    setSearchResults(filtered);
  };

  // Sample product data
  const recentProducts = [
    {
      id: 1,
      name: "Organic Broccoli",
      category: "Cruciferous",
      price: "12.99",
      originalPrice: "15.99",
      sale: true,
      image: "https://images.unsplash.com/photo-1459411621453-7b03977f4bfc?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 2,
      name: "Fresh Chickpea",
      category: "Chickpea",
      price: "8.50",
      image: "https://images.unsplash.com/photo-1586380951431-59c8d2c9c3b5?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 3,
      name: "Organic Spinach",
      category: "Leafy Greens",
      price: "6.75",
      originalPrice: "8.99",
      sale: true,
      image: "https://images.unsplash.com/photo-1515543237350-b3eea1ec8082?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 4,
      name: "Fresh Broad Beans",
      category: "Broad Beans",
      price: "10.25",
      image: "https://images.unsplash.com/photo-1498579809087-ef1e558fd1da?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 9,
      name: "Organic Turmeric",
      category: "Herbs & Spices",
      price: "15.99",
      image: "https://images.unsplash.com/photo-1615485290382-441e4d049cb5?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 10,
      name: "Fresh Ginger Root",
      category: "Herbs & Spices",
      price: "7.50",
      originalPrice: "9.99",
      sale: true,
      image: "https://images.unsplash.com/photo-1545807962-45ad0dea8b3b?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    }
  ];

  const bestSellers = [
    {
      id: 5,
      name: "Organic Kale",
      category: "Leafy Greens",
      price: "7.99",
      image: "https://images.unsplash.com/photo-1515543237350-b3eea1ec8082?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 6,
      name: "Fresh Carrots",
      category: "Root Vegetables",
      price: "5.50",
      originalPrice: "7.00",
      sale: true,
      image: "https://images.unsplash.com/photo-1582515073490-39981397c445?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 7,
      name: "Organic Tomatoes",
      category: "Nightshades",
      price: "9.75",
      image: "https://images.unsplash.com/photo-1546470427-e271e2544d7e?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 8,
      name: "Fresh Bell Peppers",
      category: "Nightshades",
      price: "8.99",
      image: "https://images.unsplash.com/photo-1563565375-f3fdfdbefa83?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 11,
      name: "Organic Garlic",
      category: "Herbs & Spices",
      price: "4.25",
      image: "https://images.unsplash.com/photo-1553395840-ddbf93b3f558?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    },
    {
      id: 12,
      name: "Fresh Cilantro",
      category: "Herbs & Spices",
      price: "3.99",
      originalPrice: "5.99",
      sale: true,
      image: "https://images.unsplash.com/photo-1576085898323-218337e3e43c?ixlib=rb-4.0.3&auto=format&fit=crop&w=500&q=80"
    }
  ];

  return (
    <CartProvider>
      <div className="App">
        <Navbar />
        <Hero />
        <FeaturedServices />

        <SearchSection onSearch={handleSearch} />

        {searchResults ? (
          <ProductSection 
            title="Search Results"
            products={searchResults}
          />
        ) : (
          <>
            <ProductSection 
              title="Recently Added Our Store"
              products={recentProducts}
            />

            <PromoBanner 
              discount="50% OFF"
              title="Enjoy Your Favorite Salad"
              subtitle="Fresh, organic ingredients delivered to your doorstep"
              backgroundImage="https://images.unsplash.com/photo-1512621776951-a57141f2eefd?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80"
              textAlign="left"
            />

            <ProductSection 
              title="Best Selling Products"
              products={bestSellers}
            />
          </>
        )}
      </div>
    </CartProvider>
  );
}

export default App;
